function officialStat({
  id,
  datasetId,
  datasetType,
  categoryGroup,
  year,
  commodityName,
  regencyCode = null,
  regencyName = "Nusa Tenggara Timur",
  scope = "province",
  metric1Label = null,
  metric1Value = null,
  metric1Unit = null,
  metric2Label = null,
  metric2Value = null,
  metric2Unit = null,
  metric3Label = null,
  metric3Value = null,
  metric3Unit = null,
  metric4Label = null,
  metric4Value = null,
  metric4Unit = null,
  productionValue = null,
  productionUnit = null,
  productivityValue = null,
  productivityUnit = null,
  households = null,
  sourceDataset,
  sourceInstitution,
  notes = ""
}) {
  return {
    id,
    datasetId,
    datasetType,
    categoryGroup,
    year,
    commodityName,
    regencyCode,
    regencyName,
    scope,
    metric1Label,
    metric1Value,
    metric1Unit,
    metric2Label,
    metric2Value,
    metric2Unit,
    metric3Label,
    metric3Value,
    metric3Unit,
    metric4Label,
    metric4Value,
    metric4Unit,
    productionValue,
    productionUnit,
    productivityValue,
    productivityUnit,
    households,
    sourceDataset,
    sourceInstitution,
    notes,
    isOfficial: true
  };
}

